584 /// Helper to describe and deal with positions in the LLVM-IR.
585 ///
586 /// A position in the IR is described by an anchor value and an "offset" that
587 /// could be the argument number, for call sites and arguments, or an indicator
588 /// of the "position kind". The kinds, specified in the Kind enum below, include
589 /// the locations in the attribute list, i.a., function scope and return value,
590 /// as well as a distinction between call sites and functions. Finally, there
591 /// are floating values that do not have a corresponding attribute list
592 /// position.
593 struct IRPosition {
594   // NOTE: In the future this definition can be changed to support recursive
595   // functions.
596   using CallBaseContext = CallBase;
597 
598   /// The positions we distinguish in the IR.
599   enum Kind : char {
600     IRP_INVALID,  ///< An invalid position.
601     IRP_FLOAT,    ///< A position that is not associated with a spot suitable
602                   ///< for attributes. This could be any value or instruction.
603     IRP_RETURNED, ///< An attribute for the function return value.
604     IRP_CALL_SITE_RETURNED, ///< An attribute for a call site return value.
605     IRP_FUNCTION,           ///< An attribute for a function (scope).
606     IRP_CALL_SITE,          ///< An attribute for a call site (function scope).
607     IRP_ARGUMENT,           ///< An attribute for a function argument.
608     IRP_CALL_SITE_ARGUMENT, ///< An attribute for a call site argument.
609   };
610 
611   /// Default constructor available to create invalid positions implicitly. All
612   /// other positions need to be created explicitly through the appropriate
613   /// static member function.
614   IRPosition() : Enc(nullptr, ENC_VALUE) { verify(); }
615 
616   /// Create a position describing the value of \p V.
617   static const IRPosition value(const Value &V,
618                                 const CallBaseContext *CBContext = nullptr) {
619     if (auto *Arg = dyn_cast<Argument>(&V))
620       return IRPosition::argument(*Arg, CBContext);
621     if (auto *CB = dyn_cast<CallBase>(&V))
622       return IRPosition::callsite_returned(*CB);
623     return IRPosition(const_cast<Value &>(V), IRP_FLOAT, CBContext);
624   }
625 
626   /// Create a position describing the instruction \p I. This is different from
627   /// the value version because call sites are treated as intrusctions rather
628   /// than their return value in this function.
629   static const IRPosition inst(const Instruction &I,
630                                const CallBaseContext *CBContext = nullptr) {
631     return IRPosition(const_cast<Instruction &>(I), IRP_FLOAT, CBContext);
632   }
633 
634   /// Create a position describing the function scope of \p F.
635   /// \p CBContext is used for call base specific analysis.
636   static const IRPosition function(const Function &F,
637                                    const CallBaseContext *CBContext = nullptr) {
638     return IRPosition(const_cast<Function &>(F), IRP_FUNCTION, CBContext);
639   }
640 
641   /// Create a position describing the returned value of \p F.
642   /// \p CBContext is used for call base specific analysis.
643   static const IRPosition returned(const Function &F,
644                                    const CallBaseContext *CBContext = nullptr) {
645     return IRPosition(const_cast<Function &>(F), IRP_RETURNED, CBContext);
646   }
647 
648   /// Create a position describing the argument \p Arg.
649   /// \p CBContext is used for call base specific analysis.
650   static const IRPosition argument(const Argument &Arg,
651                                    const CallBaseContext *CBContext = nullptr) {
652     return IRPosition(const_cast<Argument &>(Arg), IRP_ARGUMENT, CBContext);
653   }
